<?php require_once 'app/models/User.php'; class AuthController{private $m;function __construct($db){$this->m=new User($db);}function login(){ $error=''; if($_SERVER['REQUEST_METHOD']=='POST'){ $u=$this->m->login($_POST['username'],$_POST['password']); if($u){$_SESSION['user_id']=$u['id'];$_SESSION['fullname']=$u['fullname'];$_SESSION['role']=$u['role'];header('Location:index.php?page=dashboard');exit;} else $error='Invalid username or password.';} include 'app/views/auth/login.php';} function logout(){session_destroy();header('Location:index.php?page=login');exit;}} ?>